      <script>
      document.querySelectorAll('.faq-item').forEach(item => {
          item.addEventListener('click', () => {
              const answer = item.querySelector('.faq-answer');
              const plus = item.querySelector('.icon-plus');
              const minus = item.querySelector('.icon-minus');
              const isOpen = answer.style.display === 'flex';

              document.querySelectorAll('.faq-answer').forEach(el => el.style.display = 'none');
              document.querySelectorAll('.icon-plus').forEach(el => el.style.display = 'block');
              document.querySelectorAll('.icon-minus').forEach(el => el.style.display = 'none');

              if (!isOpen) {
                  answer.style.display = 'flex';
                  plus.style.display = 'none';
                  minus.style.display = 'block';
              }
          });
      });
      </script>
